package randomize

import (
	"encoding/binary"

	"github.com/Psiphon-Labs/psiphon-tunnel-core/psiphon/common/prng"
	"github.com/pion/dtls/v3/pkg/crypto/hash"
	"github.com/pion/dtls/v3/pkg/crypto/signature"
	"github.com/pion/dtls/v3/pkg/crypto/signaturehash"
	"github.com/pion/dtls/v3/pkg/protocol/extension"
	"github.com/Psiphon-Labs/covert-dtls/pkg/utils"
)

// [Psiphon] ecdsaP256SHA256 is the signature algorithm that must be preserved
// at index 0 for compatibility with pion's ECDSA P-256 certificates.
var ecdsaP256SHA256 = signaturehash.Algorithm{
	Hash:      hash.SHA256,
	Signature: signature.ECDSA,
}

// [Psiphon] RandomizeExtensionUnmarshal parses and randomizes extensions.
// The Rand parameter enables deterministic replay via a seeded PRNG.
func RandomizeExtensionUnmarshal(buf []byte, r *prng.PRNG) ([]extension.Extension, error) {
	switch {
	case len(buf) == 0:
		return []extension.Extension{}, nil
	case len(buf) < 2:
		return nil, errBufferTooSmall
	}

	declaredLen := binary.BigEndian.Uint16(buf)
	if len(buf)-2 != int(declaredLen) {
		return nil, errLengthMismatch
	}

	extensions := []extension.Extension{}
	unmarshalAndAppend := func(data []byte, e extension.Extension) error {
		err := e.Unmarshal(data)
		if err != nil {
			return err
		}
		extensions = append(extensions, e)
		return nil
	}

	for offset := 2; offset < len(buf); {
		if len(buf) < (offset + 2) {
			return nil, errBufferTooSmall
		}
		var err error
		switch extension.TypeValue(binary.BigEndian.Uint16(buf[offset:])) {
		case extension.ServerNameTypeValue:
			err = unmarshalAndAppend(buf[offset:], &extension.ServerName{})
		case extension.SupportedEllipticCurvesTypeValue:
			e := &extension.SupportedEllipticCurves{}
			err = e.Unmarshal(buf[offset:])
			if err != nil {
				return nil, err
			}
			e.EllipticCurves = utils.ShuffleRandomLength(e.EllipticCurves, true, r)
			extensions = append(extensions, e)
		case extension.SupportedPointFormatsTypeValue:
			// [Psiphon] Add point format shuffle and truncation
			e := &extension.SupportedPointFormats{}
			err = e.Unmarshal(buf[offset:])
			if err != nil {
				return nil, err
			}
			e.PointFormats = utils.ShuffleRandomLength(e.PointFormats, true, r)
			extensions = append(extensions, e)
		case extension.SupportedSignatureAlgorithmsTypeValue:
			e := &extension.SupportedSignatureAlgorithms{}
			err = e.Unmarshal(buf[offset:])
			if err != nil {
				return nil, err
			}
			e.SignatureHashAlgorithms = utils.ShuffleRandomLength(e.SignatureHashAlgorithms, true, r)
			// [Psiphon] Pin ECDSA P-256 SHA-256 at index 0 for compatibility
			// with the ECDSA P-256 certificates generated by pion/webrtc:
			// https://github.com/pion/webrtc/blob/1df634e1188e06c08fe87753c7bdd576a29e0c92/dtlstransport.go#L84-L92
			pinECDSAP256(&e.SignatureHashAlgorithms)
			extensions = append(extensions, e)
		case extension.UseSRTPTypeValue:
			e := &extension.UseSRTP{}
			err = e.Unmarshal(buf[offset:])
			if err != nil {
				return nil, err
			}
			e.ProtectionProfiles = utils.ShuffleRandomLength(e.ProtectionProfiles, true, r)
			extensions = append(extensions, e)
		case extension.ALPNTypeValue:
			err = unmarshalAndAppend(buf[offset:], &extension.ALPN{})
		case extension.UseExtendedMasterSecretTypeValue:
			err = unmarshalAndAppend(buf[offset:], &extension.UseExtendedMasterSecret{})
		case extension.RenegotiationInfoTypeValue:
			err = unmarshalAndAppend(buf[offset:], &extension.RenegotiationInfo{})
		default:
			// [Psiphon] Preserve unknown extensions using FakeExt instead of
			// silently dropping them, which could cause handshake failures.
			err = unmarshalAndAppend(buf[offset:], &utils.FakeExt{})
		}
		if err != nil {
			return nil, err
		}
		if len(buf) < (offset + 4) {
			return nil, errBufferTooSmall
		}
		extensionLength := binary.BigEndian.Uint16(buf[offset+2:])
		offset += (4 + int(extensionLength))
	}
	return extensions, nil
}

// [Psiphon] pinECDSAP256 ensures that the ECDSA P-256 SHA-256 signature
// algorithm is at index 0 in the list. If it was truncated away, it is
// re-added. If it is present but not first, it is swapped to first.
// This is required for compatibility with pion's default ECDSA certificates.
func pinECDSAP256(algs *[]signaturehash.Algorithm) {
	for i, alg := range *algs {
		if alg.Hash == ecdsaP256SHA256.Hash && alg.Signature == ecdsaP256SHA256.Signature {
			if i != 0 {
				// Swap to first position
				(*algs)[0], (*algs)[i] = (*algs)[i], (*algs)[0]
			}
			return
		}
	}

	// Not present -- prepend it
	*algs = append([]signaturehash.Algorithm{ecdsaP256SHA256}, *algs...)
}
